text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      "공개 릴리스 목표 시각은 스모크 테스트가 통과하는 경우에 한해 금요일 15:00 KST로 잡았다.",
      "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 스크립트는 계약 자체가 잘못된 경우에만 검토하기로 했다.",
      "Minjun은 금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유하기로 했다.",
      "Doyun은 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성하기로 했다."
    ],
    "rejected_proposals": [
      "Hara가 제안한 smoke-theme-pack.mjs의 packageName 불일치 무시 방안은 거절되었다."
    ],
    "internal_stretch_goals": [
      "수요일 공개 릴리스 제안은 내부 스트레치 목표로만 남겼다."
    ],
    "non_decisions": [
      "README 설치 단계 검토는 가능하면 목요일까지 보자는 의견만 있었고, 담당자는 정해지지 않았다.",
      "Hara의 생성된 tarball 경로 확인은 Minjun의 스모크 결과 게시 이후에 진행하기로 했지만, 정확한 마감 시각은 정해지지 않았다."
    ],
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한은 누구에게 있는가?",
      "내부 수요일 스트레치 목표를 릴리스 노트에 언급할지 결정되지 않았다."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "pending",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "pending",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "Minjun의 스모크 결과 게시 후",
      "status": "pending",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 결과가 실제로 통과했는지 확인한다.",
      "tarball 경로가 기대 경로와 일치하는지 확인한다.",
      "README 설치 단계가 최신인지 검토할 담당자와 시점을 정한다.",
      "최종 릴리스 승인 권한과 릴리스 노트에 내부 스트레치 목표를 적을지 여부를 확정한다."
    ],
    "do_not_invent": [
      "고객명, 외부 파트너명, 예산, 보안 사고, 생산 장애, 법적 승인 요구사항은 추가하지 않는다.",
      "명시되지 않은 소유자, 마감일, 승인권자, 결과, 원인, 일정 확정은 추정하지 않는다.",
      "수요일 릴리스를 최종 결정으로 바꾸지 않는다.",
      "README 검토 담당자를 임의로 배정하지 않는다."
    ]
  },
  "non_invention_rules": [
    "공개 안전한 합성 메모에 명시된 사실만 사용한다.",
    "확인된 결정과 제안, 거절안, 스트레치 목표, 리스크, 열린 질문을 섞지 않는다.",
    "명시되지 않은 고객, 예산, 보안, 장애, 법무, 소유자, 마감일 사실은 만들지 않는다.",
    "불확실한 내용은 '미정', '미지정', '열린 질문'으로 유지한다."
  ]
}
